"use strict";(globalThis.webpackChunkship_it_book=globalThis.webpackChunkship_it_book||[]).push([[896],{3218(e,t,o){o.r(t),o.d(t,{assets:()=>a,contentTitle:()=>l,default:()=>u,frontMatter:()=>r,metadata:()=>n,toc:()=>h});const n=JSON.parse('{"id":"part-2-find-the-problem/chapter-2-3-problem-first-thinking","title":"Chapter 2.3 \u2014 Problem-First vs Solution-First Thinking","description":"The one mental shift that changes everything.","source":"@site/docs/part-2-find-the-problem/chapter-2-3-problem-first-thinking.mdx","sourceDirName":"part-2-find-the-problem","slug":"/part-2-find-the-problem/chapter-2-3-problem-first-thinking","permalink":"/ship-it-book/part-2-find-the-problem/chapter-2-3-problem-first-thinking","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"title":"Chapter 2.3 \u2014 Problem-First vs Solution-First Thinking","description":"The one mental shift that changes everything.","sidebar_label":"2.3 \u2014 Problem-First vs Solution-First"},"sidebar":"book","previous":{"title":"2.2 \u2014 Reading Markets Without an MBA","permalink":"/ship-it-book/part-2-find-the-problem/chapter-2-2-reading-markets"},"next":{"title":"Part 3 \u2014 Design the Solution","permalink":"/ship-it-book/part-3-design-the-solution/"}}');var s=o(4848),i=o(8453);const r={title:"Chapter 2.3 \u2014 Problem-First vs Solution-First Thinking",description:"The one mental shift that changes everything.",sidebar_label:"2.3 \u2014 Problem-First vs Solution-First"},l="Problem-First vs Solution-First Thinking",a={},h=[{value:"The Solution-First Trap",id:"the-solution-first-trap",level:2},{value:"Famous Solution-First Failures",id:"famous-solution-first-failures",level:2},{value:"The Five Whys Technique for Finding Root Problems",id:"the-five-whys-technique-for-finding-root-problems",level:2},{value:"How to Write a Problem Hypothesis Document",id:"how-to-write-a-problem-hypothesis-document",level:2},{value:"Case Study: Airbnb&#39;s Problem-First Approach",id:"case-study-airbnbs-problem-first-approach",level:2},{value:"How Problem-First Works",id:"how-problem-first-works",level:2},{value:"The Problem Statement Template",id:"the-problem-statement-template",level:2},{value:"The Pivot from Solution to Problem Mindset",id:"the-pivot-from-solution-to-problem-mindset",level:2},{value:"The Hard Truth",id:"the-hard-truth",level:2},{value:"Your Turn",id:"your-turn",level:2},{value:"What You Learned",id:"what-you-learned",level:2}];function d(e){const t={code:"code",h1:"h1",h2:"h2",header:"header",li:"li",ol:"ol",p:"p",pre:"pre",strong:"strong",ul:"ul",...(0,i.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"problem-first-vs-solution-first-thinking",children:"Problem-First vs Solution-First Thinking"})}),"\n",(0,s.jsx)(t.p,{children:'Most developers start with a solution. "I\'m going to build an AI-powered project management tool." They fall in love with their solution. They spend months building it. Then they discover nobody wants it.'}),"\n",(0,s.jsx)(t.p,{children:'Problem-first thinkers start with a question. "Why do teams struggle to keep their projects on track?" They explore the problem deeply. They talk to teams. They watch them work. Only after they understand the problem do they start thinking about solutions.'}),"\n",(0,s.jsx)(t.p,{children:"This chapter is about making the shift from solution-first to problem-first. It's the single most important mental model in building products."}),"\n",(0,s.jsx)(t.h2,{id:"the-solution-first-trap",children:"The Solution-First Trap"}),"\n",(0,s.jsx)(t.p,{children:"Solution-first thinking feels productive. You're building something concrete. You can show progress. You can write code. You feel like you're moving."}),"\n",(0,s.jsx)(t.p,{children:"But solution-first thinking shortcuts the most important part of building: understanding the problem. When you start with a solution, you:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"Build features nobody asked for"}),"\n",(0,s.jsx)(t.li,{children:"Solve problems nobody has"}),"\n",(0,s.jsx)(t.li,{children:"Create complexity where simplicity was needed"}),"\n",(0,s.jsx)(t.li,{children:"Fall in love with your idea and ignore evidence against it"}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"Every failed startup I've been part of failed because we had a solution looking for a problem. We built beautiful code for a market that didn't exist."}),"\n",(0,s.jsx)(t.h2,{id:"famous-solution-first-failures",children:"Famous Solution-First Failures"}),"\n",(0,s.jsx)(t.p,{children:"These failures cost millions and taught the industry hard lessons about what happens when you prioritize solution over problem."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Juicero"})," raised $120 million to build a Wi-Fi-enabled juice press. The machine was beautiful. It had a four-ton press mechanism, custom packaging, and an app. The problem? Nobody needed a $700 juicer. The real problem \u2014 getting fresh juice conveniently \u2014 was already solved by juice bottles at the grocery store. When users discovered they could squeeze the juice packs by hand (the machine wasn't actually necessary), the company collapsed. A solution in search of a problem, funded to the tune of nine figures."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Google Glass"}),' was a technological marvel. Augmented reality glasses with a camera, display, and voice control. Google spent years and billions of dollars on R&D. The problem? Nobody asked for it. The pitch was "a device that puts information in your field of vision." But what problem did that solve? Who woke up thinking "I wish I had a screen on my face"? Google assumed the technology was so impressive that people would find uses for it. They were wrong. The device was rejected by consumers, banned from public spaces, and eventually discontinued for the mass market.']}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Quibi"})," raised $1.75 billion to build a mobile-first streaming platform with short-form content from Hollywood talent. The founders assumed that people wanted premium short-form video on their phones. But the problem wasn't \"how do I watch short videos on my phone?\" \u2014 that was already solved by YouTube, TikTok, and Instagram for free. Quibi had no answer for why people needed a paid subscription for something they were already getting. They spent billions building a solution to a problem that didn't exist."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Color Labs"})," raised $41 million to build a location-based photo-sharing app before launching. They had no users, no product, just a vision. The assumption was that people wanted to share photos with nearby strangers. That assumption was never validated. The product launched, nobody cared, and the company shut down. The funding was based on the solution, not the problem."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Windows Vista"})," was a massive solution-first project at Microsoft. Teams spent years adding features no one asked for: a new graphics subsystem, a sidebar with gadgets, elaborate security prompts. The problem was that users wanted a stable, secure, fast operating system. Vista solved for innovation instead of reliability. It became one of the most widely rejected software releases in history."]}),"\n",(0,s.jsx)(t.p,{children:"The pattern is consistent across all these failures: brilliant people, impressive technology, and no real problem at the core."}),"\n",(0,s.jsx)(t.h2,{id:"the-five-whys-technique-for-finding-root-problems",children:"The Five Whys Technique for Finding Root Problems"}),"\n",(0,s.jsx)(t.p,{children:'The surface-level problem is rarely the real problem. If someone says "I need a better to-do list app," the real problem might be "I feel overwhelmed by my workload because I don\'t have a system for prioritization."'}),"\n",(0,s.jsx)(t.p,{children:"The Five Whys technique helps you dig past surface complaints to root problems. Originally developed by Sakichi Toyoda for Toyota's manufacturing processes, it works just as well for product discovery."}),"\n",(0,s.jsx)(t.p,{children:"Here's how it works:"}),"\n",(0,s.jsx)(t.p,{children:'Start with a complaint or surface problem. Ask "why?" Then ask "why?" again. Repeat five times.'}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:'Example: Freelance developer says "I need better invoicing software"'})}),"\n",(0,s.jsxs)(t.ol,{children:["\n",(0,s.jsxs)(t.li,{children:["\n",(0,s.jsx)(t.p,{children:'Why? "Because creating invoices takes too long."'}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"Surface problem: Invoicing is slow."}),"\n"]}),"\n"]}),"\n",(0,s.jsxs)(t.li,{children:["\n",(0,s.jsx)(t.p,{children:'Why does it take too long? "Because I have to manually enter hours, rates, and client details every time."'}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"One level deeper: Lack of automation."}),"\n"]}),"\n"]}),"\n",(0,s.jsxs)(t.li,{children:["\n",(0,s.jsx)(t.p,{children:'Why do you manually enter everything? "Because my time tracking is in one tool and invoices are in another."'}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"Two levels deep: Tool fragmentation."}),"\n"]}),"\n"]}),"\n",(0,s.jsxs)(t.li,{children:["\n",(0,s.jsx)(t.p,{children:'Why are they separate? "Because I never set up a proper workflow. I just use whatever tools I find first."'}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"Three levels deep: No systematic approach."}),"\n"]}),"\n"]}),"\n",(0,s.jsxs)(t.li,{children:["\n",(0,s.jsx)(t.p,{children:"Why haven't you set up a proper workflow? \"Because I don't think of myself as a business. I think of myself as a developer who happens to do freelance work.\""}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"Root cause: Identity misalignment. They don't manage their business because they don't identify as a business owner."}),"\n"]}),"\n"]}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:'Now the real problem is clear. It\'s not "invoicing software." It\'s "freelance developers who don\'t see themselves as business owners fail to manage their finances." The solution might be education and templates, not another invoicing app.'}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:'Another example: "I need a better project management tool"'})}),"\n",(0,s.jsxs)(t.ol,{children:["\n",(0,s.jsx)(t.li,{children:'Why? "Because we keep missing deadlines."'}),"\n",(0,s.jsx)(t.li,{children:'Why? "Because tasks fall through the cracks."'}),"\n",(0,s.jsx)(t.li,{children:'Why? "Because we assign tasks but don\'t track progress."'}),"\n",(0,s.jsx)(t.li,{children:'Why? "Because our standup meetings don\'t catch stalled work."'}),"\n",(0,s.jsx)(t.li,{children:"Why? \"Because people don't want to admit they're stuck in front of their team.\""}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"Root cause: Psychological safety, not project management. Teams don't need better tools. They need a blameless way to flag blocked work."}),"\n",(0,s.jsx)(t.p,{children:"The Five Whys prevents you from building a solution to the wrong problem. Use it with every customer conversation. Keep asking why until you hit something you can actually solve."}),"\n",(0,s.jsx)(t.h2,{id:"how-to-write-a-problem-hypothesis-document",children:"How to Write a Problem Hypothesis Document"}),"\n",(0,s.jsx)(t.p,{children:"A problem hypothesis document is the deliverable from your problem exploration phase. It should be written before any code is written. It's your North Star."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Template:"})}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{children:'# Problem Hypothesis Document\n\n## Problem Statement\n[Target user] struggles with [specific problem] because [root cause]. This leads to [negative outcome].\n\n## Evidence\n- Evidence type 1 (e.g., conversation with user): [summary]\n- Evidence type 2 (e.g., Reddit thread with 500 upvotes): [summary]\n- Evidence type 3 (e.g., existing solution gaps): [summary]\n\n## Users\nWho has this problem? Be specific. Not "small businesses." "Freelance designers with 1-5 clients who do their own invoicing."\n\n## Current Solutions\nWhat do people use today to solve or cope with this problem?\n- Solution A (commercial product): [strengths] / [weaknesses]\n- Solution B (spreadsheet/manual): [strengths] / [weaknesses]\n- Solution C (doing nothing): [strengths] / [weaknesses]\n\n## The Gap\nWhat do existing solutions miss? Where do they all fail together?\n\n## Risks\nWhat could be wrong with our problem hypothesis?\n- Risk 1: The problem might not be painful enough\n- Risk 2: The users might not be reachable\n- Risk 3: The problem might be solvable but not monetizable\n\n## Next Questions\nWhat do we still not know? What\'s the next conversation we need to have?\n'})}),"\n",(0,s.jsx)(t.p,{children:"Write this document before you write any code. Share it with potential users. Ask them what's wrong with it. Refine it based on their feedback. By the time you start building, your problem hypothesis should be sharp enough to guide every decision."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Real-world example:"})}),"\n",(0,s.jsx)(t.p,{children:"When building Remote OK, Pieter Levels's problem hypothesis might have looked like:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"Problem: People looking for remote jobs can't find quality listings because existing job boards mix remote and on-site positions with no filtering."}),"\n",(0,s.jsx)(t.li,{children:'Evidence: Multiple Reddit threads complaining about LinkedIn and Indeed\'s poor filtering. Twitter discussions about "I want to work remote but where do I even look?"'}),"\n",(0,s.jsx)(t.li,{children:"Users: Digital nomads, remote-first workers, people who live in areas with no local tech jobs."}),"\n",(0,s.jsx)(t.li,{children:"Current solutions: LinkedIn (bad filtering), We Work Remotely (limited listings), networking (unreliable)."}),"\n",(0,s.jsx)(t.li,{children:"The gap: No single source of truth for quality remote jobs that's updated daily."}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"This document would have told him exactly what to build and for whom."}),"\n",(0,s.jsx)(t.h2,{id:"case-study-airbnbs-problem-first-approach",children:"Case Study: Airbnb's Problem-First Approach"}),"\n",(0,s.jsx)(t.p,{children:"Airbnb is one of the most famous examples of problem-first thinking in startup history, but not for the reason most people think."}),"\n",(0,s.jsx)(t.p,{children:'The common story: "Airbnb founders rented out air mattresses during a conference and realized people would pay for short-term rentals." That\'s the surface version.'}),"\n",(0,s.jsx)(t.p,{children:"The real story: The founders, Brian Chesky and Joe Gebbia, were designers. When they started Airbnb, they didn't build a solution first. They explored the problem deeply."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"The problem they identified:"})," Travelers wanted authentic, affordable experiences in real neighborhoods, not generic hotels. Homeowners had spare space they weren't using. Both groups had a matching problem, but no marketplace connected them."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"The problem validation:"})," They didn't just assume this. They personally hosted the first guests. They talked to every early user. They stayed in hosts' homes. They experienced the problem from both sides."]}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"What they discovered by going deep on the problem:"})}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"The booking problem wasn't just about finding a place. It was about trust. Would I feel safe staying in a stranger's home? Would I feel safe hosting a stranger?"}),"\n",(0,s.jsx)(t.li,{children:"The quality problem wasn't about features. It was about photos. Listings with professional photos got 2-3x more bookings."}),"\n",(0,s.jsx)(t.li,{children:"The adoption problem wasn't about awareness. It was about fear. People were interested but scared to try."}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"Each of these discoveries led to specific solutions:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"Trust problem \u2192 Verified profiles, reviews, secure payments"}),"\n",(0,s.jsx)(t.li,{children:"Photo quality problem \u2192 Hired professional photographers for listings"}),"\n",(0,s.jsx)(t.li,{children:"Adoption problem \u2192 Easy first booking with money-back guarantee"}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"If Airbnb had started solution-first, they might have built a booking platform and wondered why nobody used it. The trust, photo, and fear problems would have remained invisible."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Their pivot within the problem:"}),' Airbnb didn\'t start with "we\'re building a marketplace." They started with "we\'re helping people find affordable places to stay." That framing let them explore the full problem space, not just the booking transaction.']}),"\n",(0,s.jsx)(t.h2,{id:"how-problem-first-works",children:"How Problem-First Works"}),"\n",(0,s.jsx)(t.p,{children:"Problem-first thinking is a discipline. It requires you to resist the urge to build until you understand the problem at a deep level."}),"\n",(0,s.jsx)(t.p,{children:'Start with a hypothesis. "I think teams struggle with project management because they have too many tools and no single source of truth."'}),"\n",(0,s.jsx)(t.p,{children:"Now test that hypothesis. Talk to teams. Watch them work. See if your hypothesis holds up. You'll almost certainly discover you're wrong about some things and right about others. That's the point."}),"\n",(0,s.jsx)(t.p,{children:"Each conversation refines your understanding. The problem statement changes. Gets sharper. By the time you start building, you know exactly what you're solving and for whom."}),"\n",(0,s.jsx)(t.h2,{id:"the-problem-statement-template",children:"The Problem Statement Template"}),"\n",(0,s.jsx)(t.p,{children:"A good problem statement follows this structure:"}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{children:"[Target user] struggles with [specific problem] because [root cause]. \nThis leads to [negative outcome].\n"})}),"\n",(0,s.jsx)(t.p,{children:'Example: "Freelance developers struggle to track their project finances because they use spreadsheets designed for accountants. This leads to tax errors, missed deductions, and financial stress."'}),"\n",(0,s.jsx)(t.p,{children:"Notice what this doesn't include: a solution. No mention of an app, a dashboard, or a feature. Just the user, their problem, the cause, and the outcome."}),"\n",(0,s.jsx)(t.p,{children:'A well-written problem statement should make the solution almost obvious. If you read "freelance developers struggle with project finances because they use accountant spreadsheets," the solution practically writes itself: a finance tool designed for non-accountants with the terminology and workflow of a freelancer.'}),"\n",(0,s.jsx)(t.p,{children:"If your problem statement doesn't suggest a clear solution space, you haven't gone deep enough."}),"\n",(0,s.jsx)(t.h2,{id:"the-pivot-from-solution-to-problem-mindset",children:"The Pivot from Solution to Problem Mindset"}),"\n",(0,s.jsx)(t.p,{children:'Making the mental shift from "I want to build X" to "I want to solve Y" is the hardest change you\'ll make as a builder. Here\'s how to do it.'}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Change your language:"})}),"\n",(0,s.jsx)(t.p,{children:'When someone asks what you\'re working on, don\'t say "I\'m building an app." Say "I\'m exploring how freelancers manage their finances." Or "I\'m researching why teams struggle with remote work."'}),"\n",(0,s.jsx)(t.p,{children:'This isn\'t just semantics. It changes the conversation. When you say "I\'m building an app," people either compliment you or pitch their own ideas. When you say "I\'m exploring a problem," people share their experiences. One gives you noise. The other gives you data.'}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Change your calendar:"})}),"\n",(0,s.jsx)(t.p,{children:"Schedule time for problem exploration before you schedule time for building. Block two weeks for research. No code allowed. If you can't help yourself, build a prototype in the second week \u2014 but only to validate what you learned, not to create the final product."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Change your success metric:"})}),"\n",(0,s.jsx)(t.p,{children:"Right now you probably measure success by what you've built. Lines of code. Features shipped. Apps launched. Problem-first thinking measures success by what you've learned. How many conversations did you have? How much did your understanding improve? How many assumptions did you invalidate?"}),"\n",(0,s.jsx)(t.p,{children:'When learning is your metric, "I discovered nobody has this problem" is a successful outcome. It saved you months of wasted building.'}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Change your reaction to negative feedback:"})}),"\n",(0,s.jsx)(t.p,{children:'When someone tells you your idea won\'t work, do you defend it? Or do you say "tell me more" and take notes?'}),"\n",(0,s.jsx)(t.p,{children:"The pivot happens when you stop treating your idea as precious and start treating the problem as precious. Your idea is disposable. The problem is permanent. If you solve the real problem, multiple solutions will emerge. If you're married to one solution, you'll miss better ones."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"The confidence paradox:"})}),"\n",(0,s.jsx)(t.p,{children:"You might worry that problem-first thinking will make you less confident. That exploring the problem will reveal how little you know."}),"\n",(0,s.jsx)(t.p,{children:"This is true. And it's good."}),"\n",(0,s.jsx)(t.p,{children:'Confidence before understanding is hubris. Confidence after understanding is real confidence. The builder who says "I\'ve talked to 20 potential users, I\'ve used all five competitors, and I know exactly what gap exists" is far more likely to succeed than the builder who says "I have a great idea, trust me."'}),"\n",(0,s.jsx)(t.p,{children:"Embrace the uncertainty of exploration. It's the only path to genuine certainty."}),"\n",(0,s.jsx)(t.h2,{id:"the-hard-truth",children:"The Hard Truth"}),"\n",(0,s.jsx)(t.p,{children:"Solution-first thinking feels safer because it keeps you in your comfort zone: building. Problem-first thinking forces you into discomfort: uncertainty, ambiguity, and conversations with strangers."}),"\n",(0,s.jsx)(t.p,{children:"But products built solution-first rarely succeed. Products built problem-first have a fighting chance because they're solving something real."}),"\n",(0,s.jsx)(t.p,{children:"Your job is not to build a solution. Your job is to solve a problem. If you can define the problem well enough, the solution almost designs itself. If you can't define the problem, no amount of elegant code will save you."}),"\n",(0,s.jsx)(t.p,{children:"The Juicero engineers thought they were building a juicing machine. They were actually failing to ask whether anyone needed one. The Airbnb founders thought they were building a booking platform. They actually discovered they needed to solve trust, photography, and fear first."}),"\n",(0,s.jsx)(t.p,{children:"The difference between failure and success isn't the quality of the solution. It's the depth of the problem understanding."}),"\n",(0,s.jsx)(t.h2,{id:"your-turn",children:"Your Turn"}),"\n",(0,s.jsx)(t.p,{children:"Take a project idea you have. Write it down. Now write a problem statement using the template above. If you can't fill in all three parts (user, problem, root cause, outcome), you don't understand the problem well enough."}),"\n",(0,s.jsx)(t.p,{children:'Now use the Five Whys on your problem statement. Pick one aspect of the problem and ask "why" five times. What root cause did you discover? Does it change what you think the solution should be?'}),"\n",(0,s.jsx)(t.p,{children:"Now go talk to three people who might have this problem. Update your problem statement based on what you learn."}),"\n",(0,s.jsx)(t.p,{children:"Finally, write a Problem Hypothesis Document using the template in this chapter. Share it with someone who might be a user. Ask them what you're getting wrong."}),"\n",(0,s.jsx)(t.h2,{id:"what-you-learned",children:"What You Learned"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"Solution-first thinking builds solutions for problems that might not exist"}),"\n",(0,s.jsx)(t.li,{children:"Famous failures like Juicero, Google Glass, and Quibi prove solution-first kills products"}),"\n",(0,s.jsx)(t.li,{children:"The Five Whys technique helps you find root causes beneath surface complaints"}),"\n",(0,s.jsx)(t.li,{children:"A problem hypothesis document captures your understanding and guides your research"}),"\n",(0,s.jsx)(t.li,{children:"Airbnb succeeded by exploring the problem deeply before building solutions"}),"\n",(0,s.jsx)(t.li,{children:"Problem-first thinking starts with understanding before building"}),"\n",(0,s.jsx)(t.li,{children:"A good problem statement excludes the solution"}),"\n",(0,s.jsx)(t.li,{children:'Shift your language from "building X" to "solving Y"'}),"\n",(0,s.jsx)(t.li,{children:"The problem defines the solution, not the other way around"}),"\n",(0,s.jsx)(t.li,{children:"Embrace the pivot from solution-first to problem-first \u2014 it's the single most important mental shift you'll make"}),"\n"]})]})}function u(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},8453(e,t,o){o.d(t,{R:()=>r,x:()=>l});var n=o(6540);const s={},i=n.createContext(s);function r(e){const t=n.useContext(i);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function l(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:r(e.components),n.createElement(i.Provider,{value:t},e.children)}}}]);